def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        multiplier = 1.0
        adjustment = 1.0
        temp_factor = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.04 + 0.015 * j
            elif j % 6 == 0:
                multiplier *= 0.93 - 0.01 * j
            if cap % (j+3) == 0:
                penalty += np.cos(j * ratio) * 0.7
            if ratio < 0.05 * j:
                score += ((j ** 3) / (1 + np.exp(-ratio * j*2))) * multiplier
            else:
                score += ((np.log1p(j*j*j) + ratio**4) * multiplier) / (j + 1)
            if (cap * j + j*j) % 9 == 0:
                score *= 1.07
            elif (cap + j*j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(abs(diff)) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 2 == 1:
                adjustment *= 1.12 + 0.025 * j
                temp_factor *= 1 + 0.01 * j
            elif ratio < 0.15 and j % 5 == 2:
                adjustment *= 0.88 - 0.015 * j
                temp_factor *= 0.95 - 0.005 * j
            if (j + i) % 7 == 0:
                penalty += np.sin(j * ratio * 2) * 0.65
        score += penalty * 0.85 * temp_factor
        score *= adjustment
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.tanh(ratio))
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.cbrt(cap) + 1) * (1 + ratio**1.5)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.2)
        if ratio > 0.9:
            priorities[i] *= 1.18
            if cap % 5 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.03:
            priorities[i] *= 0.7
            if cap % 3 == 0:
                priorities[i] *= 0.9
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
